// Enable flow logs with retention >= 90 days for a supported target
resource flowlog 'Microsoft.Network/networkWatchers/flowLogs@2023-09-01' = {
  name: '<example_network_watcher_name>/<example_flow_log_name>'
  location: '<LOCATION>'
  properties: {
    targetResourceId: '<example_target_resource_id>'
    storageId: '<example_storage_account_id>'
    enabled: true
    retentionPolicy: {
      enabled: true
      days: 90
    }
  }
}
